2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // Quote: empty and basic items
7	  it("quote with empty item list returns premium 5 (processing fee only)", () => {
8	    expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
9	  });
10	  it("quote with a single sword (plain, no modifiers) returns premium 115 (100 base + 10 first insurance + 5 fee)", () => {
11	    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", material: "steel", enchantment: 0, cursed: false }])).toBe(115);
12	  });
13	  it.todo("quote with a single amulet (plain, no modifiers) returns premium 71 (60 base + 6 first insurance + 5 fee)");
14	  it.todo("quote with a single staff (plain, no modifiers) returns premium 93 (80 base + 8 first insurance + 5 fee)");
15	  it.todo("quote with a single potion (plain, no modifiers) returns premium 49 (40 base + 4 first insurance + 5 fee)");
16	
17	  // Quote: multiple items
18	  it.todo("quote with two plain items sums their base premiums (sword + amulet = 100 + 60 = 160 base, +16 first insurance, +5 fee = 181)");
19	
20	  // Components (runes/moonstones)
21	  it.todo("quote with 2 runes returns base premium 50 (2 × 25)");
22	  it.todo("quote with 3 runes applies block discount (60 base premium, not 75)");
23	  it.todo("quote with 4 runes returns 100 (block requires exactly 3, no block applies)");
24	  it.todo("quote with 7 runes returns 175 base premium (one block of 3 + 4 single = 60 + 100)");
25	  it.todo("quote with 2 runes + 1 moonstone returns 75 base premium (no block: different types)");
26	  it.todo("quote with 3 runes + 3 moonstones returns 120 base premium (two separate blocks)");
27	
28	  // Item-specific modifiers
29	  it.todo("quote with cursed sword adds 50% surcharge on item base premium (100 + 50 curse)");
30	  it.todo("quote with sword at enchantment 5 adds 30% surcharge on item base premium");
31	  it.todo("quote with sword at enchantment 4 does not add high-enchantment surcharge");
32	  it.todo("quote with cursed sword at enchantment 5 stacks both surcharges");
33	
34	  // Modifier scope on multi-item policies
35	  it.todo("quote with cursed sword + plain amulet applies curse only to sword's base premium (210 before policy modifiers and fee)");
36	
37	  // Policy-wide modifiers
38	  it.todo("quote with customer at exactly 2 years applies 20% loyalty discount on policy total");
39	  it.todo("quote with customer at less than 2 years does not apply loyalty discount");
40	  it.todo("quote first insurance adds 10% surcharge per item on the policy");
41	  it.todo("quote follow-up contract (after first quote in scenario) applies 15% discount on policy total");
42	
43	  // Rounding
44	  it.todo("premium calculation yielding 197.5 rounds up to 198");
45	
46	  // Integration examples from spec
47	  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) returns premium 165");
48	  it.todo("long-standing customer's second contract: cursed sword (enchantment 7, 3 years, 2nd quote) returns premium 160");
49	
50	  // Quote: error cases
51	  it.todo("quote with unknown item type causes CLI to exit non-zero with error to stderr");
52	
53	  // Claim: basic payouts
54	  it.todo("claim on regular sword (steel, enchantment 3) with damage 500 returns payout 400 (full reimbursement minus 100 deductible)");
55	  it.todo("claim on rune (insurance value 250) with damage 200 returns payout 100 (full reimbursement minus 100 deductible)");
56	
57	  // Claim: enchantment threshold
58	  it.todo("claim on steel sword enchantment 9 with damage 1000 returns payout 400 (50% reimbursement, then 100 deductible)");
59	
60	  // Claim: dragon material
61	  it.todo("claim on dragon-material sword enchantment 5 with damage 800 returns payout 700 (full reimbursement, then 100 deductible)");
62	  it.todo("claim on dragon-material sword enchantment 9 with damage 1000 returns payout 400 (50% rule wins, then deductible)");
63	  it.todo("claim on dragon-material sword enchantment 8 with damage 1000 returns payout 400 (high-enchantment clause applies, then deductible)");
64	
65	  // Claim: deductible per damage event
66	  it.todo("claim with two damaged items (sword 500 + amulet 300) applies deductible per item: payout 600");
67	
68	  // Claim: multiple items of the same type
69	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
70	  it.todo("claim with two sword damages on a two-sword policy treats each as separate damage with own deductible");
71	  it.todo("claim with more sword damages than swords insured causes CLI to exit non-zero");
72	
73	  // Claim: cap
74	  it.todo("policy with sword + amulet has insurance sum 1600 and cap 3200");
75	  it.todo("policy with sword + 3 runes has insurance sum 1750 (block discount affects premium only, not cap)");
76	  it.todo("cap is based on unmodified insurance value (cursed sword cap = 2000)");
77	  it.todo("first claim of 1500 on sword (cap 2000) returns payout 1400 with remainingCap 600");
78	  it.todo("second claim of 1500 with remainingCap 600 returns payout 600 with remainingCap 0");
79	
80	  // Claim: rounding
81	  it.todo("payout calculation yielding 350.5 rounds down to 350");
82	
83	  // Claim: error cases
84	  it.todo("claim referencing item not in policy causes CLI to exit non-zero with error to stderr");
85	  it.todo("claim with negative damage amount causes CLI to exit non-zero with error to stderr");
86	
87	  // CLI integration
88	  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout in step order");
89	});
