const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

export function quote(_customer: Customer, items: Item[]): number {
  const itemsBase = items.reduce((sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
  const withFirstInsurance = itemsBase * 1.1;
  return withFirstInsurance + PROCESSING_FEE;
}

